let publishLayerHtml=$("#publishLayerHtml").html();let blogEditor=editormd("blog-editormd",EDITOR_CONFIG);function getImgUrlFromMarkDown(a){let reg=/!\[.*?\]\((.*?)\)/im;let matches=reg.exec(a);if(matches===null||matches===undefined||matches.length===0){return IMG_DEFAULT}else{return matches[1]}}layui.use(["layer","form"],function(){let layer=layui.layer;let form=layui.form;let publishLayer;let options=[];$("#confirm").on("click",function(){publishLayer=layer.open({type:1,area:["60%"],shadeClose:true,title:"发布博客",content:publishLayerHtml,success:function(){$.ajax({url:"/blog_type",method:"GET",dataType:"json",success:function(a){if(a.request==="success"&&a.status===200){$.each(a.data,function(b,c){$("#type").append(new Option(c.name,c.name));options.push(c)});form.render()}else{layer.msg(a.message+", 错误码: "+a.status,{icon:2})}},error:function(a){if(a){layer.msg(a)}else{layer.msg("请求错误，请检查网络",{icon:2})}}})}})});form.verify({title:function(b,a){let titleRex=/^[\w\W\s\u4e00-\u9fcc]{4,30}$/;if(!titleRex.test(b)){return"标题只能为4-64个字符的字符串"}},author:function(b,a){let titleRex=/^[\w\W\s\u4e00-\u9fcc]{2,10}$/;if(!titleRex.test(b)){return"作者只能为2-10个字符"}}});form.on("submit(form-blog-submit)",function(a){let blog=a.field;layer.confirm("确认发表？",{btn:["确认","取消"]},function(b){let coverImage=getImgUrlFromMarkDown(blogEditor.getMarkdown());let contentHtml=blogEditor.getHTML();let contentMarkdown=blogEditor.getMarkdown();let blogObject={title:blog.title,author:blog.author,summary:blog.summary,type:blog.type,contentMarkdown:contentMarkdown,contentHtml:contentHtml,coverImage:coverImage};$.ajax({url:"/blog",data:blogObject,method:"POST",dateType:"json",success:function(c){if(c.request==="success"&&c.status===200){layer.msg(c.message,{icon:1})}else{layer.msg(c.message+", 错误码: "+c.status,{icon:2})}},error:function(c){if(c){layer.msg(c)}else{layer.msg("请求错误，请检查网络",{icon:2})}}});layer.close(b)});return false})});